# 3D Gallery Photography

An infinite 3D scroll gallery powered by React Three Fiber. Images are loaded as textures onto planes arranged along a depth axis. A custom cloth GLSL shader curves each plane with scroll force and adds flag-waving hover ripples. Cards fade in and out at depth boundaries and blur at the near and far edges. Auto-play advances the gallery after 3 seconds of inactivity; mouse wheel, arrow keys, and touch also control scroll.

## Use when
- Building a photography portfolio with an immersive depth-scrolling 3D viewer.
- Creating a product catalog or art gallery with a cinematic infinite-scroll effect.
- Adding a WebGL-powered image browser with cloth-physics card effects.
- Showcasing a collection of images with auto-play and keyboard navigation.

## Stack
- Framework: react
- Libraries: three, @react-three/fiber, @react-three/drei
- Requires: tailwind, shadcn

## Install
```bash
three @react-three/fiber @react-three/drei
```

## Component — 3d-gallery-photography.tsx
```tsx
import type React from 'react';
import { useRef, useMemo, useCallback, useState, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { useTexture } from '@react-three/drei';
import * as THREE from 'three';

type ImageItem = string | { src: string; alt?: string };

interface FadeSettings {
	fadeIn: { start: number; end: number };
	fadeOut: { start: number; end: number };
}

interface BlurSettings {
	blurIn: { start: number; end: number };
	blurOut: { start: number; end: number };
	maxBlur: number;
}

interface InfiniteGalleryProps {
	images: ImageItem[];
	speed?: number;
	zSpacing?: number;
	visibleCount?: number;
	falloff?: { near: number; far: number };
	fadeSettings?: FadeSettings;
	blurSettings?: BlurSettings;
	className?: string;
	style?: React.CSSProperties;
}

const DEFAULT_DEPTH_RANGE = 50;
const MAX_HORIZONTAL_OFFSET = 8;
const MAX_VERTICAL_OFFSET = 8;

const createClothMaterial = () => {
	return new THREE.ShaderMaterial({
		transparent: true,
		uniforms: {
			map: { value: null },
			opacity: { value: 1.0 },
			blurAmount: { value: 0.0 },
			scrollForce: { value: 0.0 },
			time: { value: 0.0 },
			isHovered: { value: 0.0 },
		},
		vertexShader: `
      uniform float scrollForce;
      uniform float time;
      uniform float isHovered;
      varying vec2 vUv;
      varying vec3 vNormal;
      void main() {
        vUv = uv;
        vNormal = normal;
        vec3 pos = position;
        float curveIntensity = scrollForce * 0.3;
        float distanceFromCenter = length(pos.xy);
        float curve = distanceFromCenter * distanceFromCenter * curveIntensity;
        float ripple1 = sin(pos.x * 2.0 + scrollForce * 3.0) * 0.02;
        float ripple2 = sin(pos.y * 2.5 + scrollForce * 2.0) * 0.015;
        float clothEffect = (ripple1 + ripple2) * abs(curveIntensity) * 2.0;
        float flagWave = 0.0;
        if (isHovered > 0.5) {
          float wavePhase = pos.x * 3.0 + time * 8.0;
          float dampening = smoothstep(-0.5, 0.5, pos.x);
          flagWave = sin(wavePhase) * 0.1 * dampening;
          flagWave += sin(pos.x * 5.0 + time * 12.0) * 0.03 * dampening;
        }
        pos.z -= (curve + clothEffect + flagWave);
        gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
      }
    `,
		fragmentShader: `
      uniform sampler2D map;
      uniform float opacity;
      uniform float blurAmount;
      uniform float scrollForce;
      varying vec2 vUv;
      void main() {
        vec4 color = texture2D(map, vUv);
        if (blurAmount > 0.0) {
          vec2 texelSize = 1.0 / vec2(textureSize(map, 0));
          vec4 blurred = vec4(0.0);
          float total = 0.0;
          for (float x = -2.0; x <= 2.0; x += 1.0) {
            for (float y = -2.0; y <= 2.0; y += 1.0) {
              vec2 offset = vec2(x, y) * texelSize * blurAmount;
              float weight = 1.0 / (1.0 + length(vec2(x, y)));
              blurred += texture2D(map, vUv + offset) * weight;
              total += weight;
            }
          }
          color = blurred / total;
        }
        color.rgb += vec3(abs(scrollForce) * 0.05 * 0.1);
        gl_FragColor = vec4(color.rgb, color.a * opacity);
      }
    `,
	});
};

function ImagePlane({ texture, position, scale, material }: {
	texture: THREE.Texture;
	position: [number, number, number];
	scale: [number, number, number];
	material: THREE.ShaderMaterial;
}) {
	const meshRef = useRef<THREE.Mesh>(null);
	const [isHovered, setIsHovered] = useState(false);
	useEffect(() => { if (material && texture) material.uniforms.map.value = texture; }, [material, texture]);
	useEffect(() => { if (material?.uniforms) material.uniforms.isHovered.value = isHovered ? 1.0 : 0.0; }, [material, isHovered]);
	return (
		<mesh ref={meshRef} position={position} scale={scale} material={material}
			onPointerEnter={() => setIsHovered(true)} onPointerLeave={() => setIsHovered(false)}>
			<planeGeometry args={[1, 1, 32, 32]} />
		</mesh>
	);
}

function GalleryScene({ images, speed = 1, visibleCount = 8, fadeSettings = { fadeIn: { start: 0.05, end: 0.15 }, fadeOut: { start: 0.85, end: 0.95 } }, blurSettings = { blurIn: { start: 0.0, end: 0.1 }, blurOut: { start: 0.9, end: 1.0 }, maxBlur: 3.0 } }: Omit<InfiniteGalleryProps, 'className' | 'style'>) {
	const [scrollVelocity, setScrollVelocity] = useState(0);
	const [autoPlay, setAutoPlay] = useState(true);
	const lastInteraction = useRef(Date.now());
	const normalizedImages = useMemo(() => images.map((img) => typeof img === 'string' ? { src: img, alt: '' } : img), [images]);
	const textures = useTexture(normalizedImages.map((img) => img.src));
	const materials = useMemo(() => Array.from({ length: visibleCount }, () => createClothMaterial()), [visibleCount]);
	const spatialPositions = useMemo(() => {
		return Array.from({ length: visibleCount }, (_, i) => ({
			x: (Math.sin((i * 2.618) % (Math.PI * 2)) * ((i % 3) * 1.2) * MAX_HORIZONTAL_OFFSET) / 3,
			y: (Math.cos(((i * 1.618 + Math.PI / 3)) % (Math.PI * 2)) * (((i + 1) % 4) * 0.8) * MAX_VERTICAL_OFFSET) / 4
		}));
	}, [visibleCount]);
	const totalImages = normalizedImages.length;
	const depthRange = DEFAULT_DEPTH_RANGE;
	const planesData = useRef(Array.from({ length: visibleCount }, (_, i) => ({
		index: i,
		z: visibleCount > 0 ? ((depthRange / visibleCount) * i) % depthRange : 0,
		imageIndex: totalImages > 0 ? i % totalImages : 0,
		x: spatialPositions[i]?.x ?? 0,
		y: spatialPositions[i]?.y ?? 0,
	})));
	const handleWheel = useCallback((event: WheelEvent) => {
		event.preventDefault();
		setScrollVelocity((prev) => prev + event.deltaY * 0.01 * speed);
		setAutoPlay(false);
		lastInteraction.current = Date.now();
	}, [speed]);
	const handleKeyDown = useCallback((event: KeyboardEvent) => {
		if (event.key === 'ArrowUp' || event.key === 'ArrowLeft') { setScrollVelocity((prev) => prev - 2 * speed); }
		else if (event.key === 'ArrowDown' || event.key === 'ArrowRight') { setScrollVelocity((prev) => prev + 2 * speed); }
		setAutoPlay(false); lastInteraction.current = Date.now();
	}, [speed]);
	useEffect(() => {
		const canvas = document.querySelector('canvas');
		if (canvas) {
			canvas.addEventListener('wheel', handleWheel, { passive: false });
			document.addEventListener('keydown', handleKeyDown);
			return () => { canvas.removeEventListener('wheel', handleWheel); document.removeEventListener('keydown', handleKeyDown); };
		}
	}, [handleWheel, handleKeyDown]);
	useEffect(() => {
		const interval = setInterval(() => { if (Date.now() - lastInteraction.current > 3000) setAutoPlay(true); }, 1000);
		return () => clearInterval(interval);
	}, []);
	useFrame((state, delta) => {
		if (autoPlay) setScrollVelocity((prev) => prev + 0.3 * delta);
		setScrollVelocity((prev) => prev * 0.95);
		const time = state.clock.getElapsedTime();
		materials.forEach((material) => {
			if (material?.uniforms) { material.uniforms.time.value = time; material.uniforms.scrollForce.value = scrollVelocity; }
		});
		const imageAdvance = totalImages > 0 ? visibleCount % totalImages || totalImages : 0;
		planesData.current.forEach((plane, i) => {
			let newZ = plane.z + scrollVelocity * delta * 10;
			let wrapsForward = 0, wrapsBackward = 0;
			if (newZ >= depthRange) { wrapsForward = Math.floor(newZ / depthRange); newZ -= depthRange * wrapsForward; }
			else if (newZ < 0) { wrapsBackward = Math.ceil(-newZ / depthRange); newZ += depthRange * wrapsBackward; }
			if (wrapsForward > 0 && imageAdvance > 0) plane.imageIndex = (plane.imageIndex + wrapsForward * imageAdvance) % totalImages;
			if (wrapsBackward > 0 && imageAdvance > 0) { const step = plane.imageIndex - wrapsBackward * imageAdvance; plane.imageIndex = ((step % totalImages) + totalImages) % totalImages; }
			plane.z = ((newZ % depthRange) + depthRange) % depthRange;
			plane.x = spatialPositions[i]?.x ?? 0;
			plane.y = spatialPositions[i]?.y ?? 0;
			const np = plane.z / depthRange;
			let opacity = np < fadeSettings.fadeIn.start ? 0 : np <= fadeSettings.fadeIn.end ? (np - fadeSettings.fadeIn.start) / (fadeSettings.fadeIn.end - fadeSettings.fadeIn.start) : np >= fadeSettings.fadeOut.end ? 0 : np >= fadeSettings.fadeOut.start ? 1 - (np - fadeSettings.fadeOut.start) / (fadeSettings.fadeOut.end - fadeSettings.fadeOut.start) : 1;
			let blur = np < blurSettings.blurIn.start ? blurSettings.maxBlur : np <= blurSettings.blurIn.end ? blurSettings.maxBlur * (1 - (np - blurSettings.blurIn.start) / (blurSettings.blurIn.end - blurSettings.blurIn.start)) : np > blurSettings.blurOut.end ? blurSettings.maxBlur : np >= blurSettings.blurOut.start ? blurSettings.maxBlur * ((np - blurSettings.blurOut.start) / (blurSettings.blurOut.end - blurSettings.blurOut.start)) : 0;
			const material = materials[i];
			if (material?.uniforms) { material.uniforms.opacity.value = Math.max(0, Math.min(1, opacity)); material.uniforms.blurAmount.value = Math.max(0, Math.min(blurSettings.maxBlur, blur)); }
		});
	});
	if (normalizedImages.length === 0) return null;
	return (
		<>
			{planesData.current.map((plane, i) => {
				const texture = textures[plane.imageIndex];
				const material = materials[i];
				if (!texture || !material) return null;
				const aspect = texture.image ? texture.image.width / texture.image.height : 1;
				const scale: [number, number, number] = aspect > 1 ? [2 * aspect, 2, 1] : [2, 2 / aspect, 1];
				return <ImagePlane key={plane.index} texture={texture} position={[plane.x, plane.y, plane.z - depthRange / 2]} scale={scale} material={material} />;
			})}
		</>
	);
}

function FallbackGallery({ images }: { images: ImageItem[] }) {
	const normalizedImages = useMemo(() => images.map((img) => typeof img === 'string' ? { src: img, alt: '' } : img), [images]);
	return (
		<div className="flex flex-col items-center justify-center h-full bg-gray-100 p-4">
			<p className="text-gray-600 mb-4">WebGL not supported. Showing image list:</p>
			<div className="grid grid-cols-2 md:grid-cols-3 gap-4 max-h-96 overflow-y-auto">
				{normalizedImages.map((img, i) => <img key={i} src={img.src || '/placeholder.svg'} alt={img.alt} className="w-full h-32 object-cover rounded" />)}
			</div>
		</div>
	);
}

export default function InfiniteGallery({ images, className = 'h-96 w-full', style, fadeSettings = { fadeIn: { start: 0.05, end: 0.25 }, fadeOut: { start: 0.4, end: 0.43 } }, blurSettings = { blurIn: { start: 0.0, end: 0.1 }, blurOut: { start: 0.4, end: 0.43 }, maxBlur: 8.0 } }: InfiniteGalleryProps) {
	const [webglSupported, setWebglSupported] = useState(true);
	useEffect(() => {
		try {
			const canvas = document.createElement('canvas');
			const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
			if (!gl) setWebglSupported(false);
		} catch (e) { setWebglSupported(false); }
	}, []);
	if (!webglSupported) return <div className={className} style={style}><FallbackGallery images={images} /></div>;
	return (
		<div className={className} style={style}>
			<Canvas camera={{ position: [0, 0, 0], fov: 55 }} gl={{ antialias: true, alpha: true }}>
				<GalleryScene images={images} fadeSettings={fadeSettings} blurSettings={blurSettings} />
			</Canvas>
		</div>
	);
}
```

## Demo
```tsx
import InfiniteGallery from "@/components/ui/3d-gallery-photography";

export default function DemoOne() {
  const sampleImages = [
    { src: 'https://images.unsplash.com/photo-1579546929518-9e396f3cc809?w=600&auto=format&fit=crop', alt: 'Image 1' },
    { src: 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=600&auto=format&fit=crop', alt: 'Image 2' },
    { src: 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600&auto=format&fit=crop', alt: 'Image 3' },
    { src: 'https://images.unsplash.com/photo-1511300636408-a63a89df3482?w=600&auto=format&fit=crop', alt: 'Image 4' },
    { src: 'https://images.unsplash.com/photo-1470770903676-69b98201ea1c?w=600&auto=format&fit=crop', alt: 'Image 5' },
    { src: 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=600&auto=format&fit=crop', alt: 'Image 6' },
    { src: 'https://images.unsplash.com/photo-1501854140801-50d01698950b?w=600&auto=format&fit=crop', alt: 'Image 7' },
    { src: 'https://images.unsplash.com/photo-1426604966848-d7adac402bff?w=600&auto=format&fit=crop', alt: 'Image 8' },
  ];
  return (
    <main className="min-h-screen h-full w-full">
      <InfiniteGallery
        images={sampleImages}
        speed={1.2}
        zSpacing={3}
        visibleCount={12}
        falloff={{ near: 0.8, far: 14 }}
        className="h-screen w-full rounded-lg overflow-hidden"
      />
      <div className="h-screen inset-0 pointer-events-none fixed flex items-center justify-center text-center px-3 mix-blend-exclusion text-white">
        <h1 className="font-serif text-4xl md:text-7xl tracking-tight">
          <span className="italic">Gallery</span>
        </h1>
      </div>
    </main>
  );
}
```

## Notes
- The original demo uses Unsplash image URLs from 2025 — replace with any publicly accessible images; the component accepts both `string` URLs and `{ src, alt }` objects.
- Auto-play resumes 3 seconds after the last user interaction (wheel, arrow keys).
- The GLSL blur approximation in the fragment shader uses `textureSize()` which requires GLSL 3.00 ES / WebGL2. On WebGL1-only devices, remove the blur branch or replace with a CSS `filter: blur()` post-process.
- `FallbackGallery` renders a plain CSS grid when WebGL is unavailable.
